const https = require('https');
const urlMod = require('url');
function httpReq(method, rawUrl, headers, postBody) {
  return new Promise((resolve, reject) => {
    const parsed = urlMod.parse(rawUrl);
    const opts = { hostname: parsed.hostname, path: parsed.path, method: method, headers: headers || {} };
    const req = https.request(opts, (res) => {
      let body = '';
      res.on('data', c => body += c);
      res.on('end', () => {
        let json = null;
        try { json = JSON.parse(body); } catch(e) {}
        resolve({ ok: res.statusCode >= 200 && res.statusCode < 300, status: res.statusCode, json: json, text: body });
      });
    });
    req.on('error', reject);
    if (postBody) req.write(typeof postBody === 'string' ? postBody : JSON.stringify(postBody));
    req.end();
  });
}

const SHEET_ID = '{{sheet_id}}';
const SHEET_URL = `https://docs.google.com/spreadsheets/d/${SHEET_ID}/gviz/tq?tqx=out:json&sheet=Raw_Jobs`;

try {
  const resp = await fetch(SHEET_URL);
  const text = resp.text;
  // Strip Google's prefix/suffix
  const jsonStr = text.replace(/^[^{]*/, '').replace(/[^}]*$/, '');
  const data = JSON.parse(jsonStr);
  const cols = data.table.cols.map(c => c.label);
  const jobs = data.table.rows.map(row => {
    const obj = {};
    row.c.forEach((cell, i) => {
      if (cols[i]) obj[cols[i]] = cell ? (cell.v || '') : '';
    });
    return obj;
  });
  return [{ json: { jobs, updated: new Date().toISOString(), source: 'google_sheets' } }];
} catch(e) {
  return [{ json: { jobs: [], error: e.message } }];
}
